import{_ as e,o as i,c as r,aA as l}from"./chunks/framework.DJuiNKwO.js";const x=JSON.parse('{"title":"Symbols and Abbreviations","description":"","frontmatter":{},"headers":[],"relativePath":"15-constants.md","filePath":"15-constants.md","lastUpdated":null}'),a={name:"15-constants.md"};function d(n,t,s,g,o,h){return i(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="Symbols-and-Abbreviations" tabindex="-1">Symbols and Abbreviations <a class="header-anchor" href="#Symbols-and-Abbreviations" aria-label="Permalink to &quot;Symbols and Abbreviations {#Symbols-and-Abbreviations}&quot;">​</a></h1><p>This page lists the symbols and abbreviations used in this package, following <strong>IEC 60076-7</strong> (thermal modelling of power transformers) and <strong>IEEE C57.91</strong> (loading guide for mineral-oil-immersed transformers) notation.</p><p>Where the Julia identifier differs from the standard symbol the difference is noted in the <em>Code name</em> column.</p><hr><h2 id="Temperatures" tabindex="-1">Temperatures <a class="header-anchor" href="#Temperatures" aria-label="Permalink to &quot;Temperatures {#Temperatures}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Unit</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">θ_amb</td><td style="text-align:right;">—</td><td style="text-align:right;">°C</td><td style="text-align:right;">Ambient (surrounding) temperature</td></tr><tr><td style="text-align:right;">θ_oil (θ_o)</td><td style="text-align:right;">—</td><td style="text-align:right;">°C</td><td style="text-align:right;">Top-oil temperature</td></tr><tr><td style="text-align:right;">θ_hs</td><td style="text-align:right;">—</td><td style="text-align:right;">°C</td><td style="text-align:right;">Hot-spot (winding) temperature</td></tr><tr><td style="text-align:right;">θ_boil</td><td style="text-align:right;">—</td><td style="text-align:right;">°C</td><td style="text-align:right;">Boiling point of the insulating oil</td></tr><tr><td style="text-align:right;">K</td><td style="text-align:right;"><code>K</code></td><td style="text-align:right;">p.u.</td><td style="text-align:right;">Load factor (ratio of actual to rated current, K = I / Iᵣ)</td></tr></tbody></table><hr><h2 id="Temperature-Rises" tabindex="-1">Temperature Rises <a class="header-anchor" href="#Temperature-Rises" aria-label="Permalink to &quot;Temperature Rises {#Temperature-Rises}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Unit</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">Δθ_oil,r (Δθₒᵣ)</td><td style="text-align:right;"><code>Δθ_or</code></td><td style="text-align:right;">K</td><td style="text-align:right;">Rated top-oil temperature rise above ambient</td></tr><tr><td style="text-align:right;">Δθ_oil (Δθₒ)</td><td style="text-align:right;">—</td><td style="text-align:right;">K</td><td style="text-align:right;">Instantaneous top-oil temperature rise above ambient</td></tr><tr><td style="text-align:right;">Δθ_hs,r</td><td style="text-align:right;">—</td><td style="text-align:right;">K</td><td style="text-align:right;">Rated hot-spot temperature rise above top-oil</td></tr><tr><td style="text-align:right;">Δθ_hs</td><td style="text-align:right;">—</td><td style="text-align:right;">K</td><td style="text-align:right;">Instantaneous hot-spot temperature rise above top-oil</td></tr><tr><td style="text-align:right;">Δθ_amb</td><td style="text-align:right;"><code>Δθ_amb</code></td><td style="text-align:right;">K</td><td style="text-align:right;">Ambient temperature correction / surcharge</td></tr><tr><td style="text-align:right;">Δθ_end</td><td style="text-align:right;"><code>Δθ_end</code></td><td style="text-align:right;">K</td><td style="text-align:right;">Steady-state end-temperature correction</td></tr></tbody></table><hr><h2 id="Thermal-Time-Constants" tabindex="-1">Thermal Time Constants <a class="header-anchor" href="#Thermal-Time-Constants" aria-label="Permalink to &quot;Thermal Time Constants {#Thermal-Time-Constants}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Unit</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">τ_oil,rated (τₒ)</td><td style="text-align:right;"><code>τ_oil</code></td><td style="text-align:right;">min</td><td style="text-align:right;">Oil thermal time constant at rated load</td></tr><tr><td style="text-align:right;">τ_wdn,rated (τ_w)</td><td style="text-align:right;"><code>τ_w</code></td><td style="text-align:right;">min</td><td style="text-align:right;">Winding thermal time constant at rated load</td></tr></tbody></table><hr><h2 id="Losses" tabindex="-1">Losses <a class="header-anchor" href="#Losses" aria-label="Permalink to &quot;Losses {#Losses}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Unit</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">P_o (no-load loss)</td><td style="text-align:right;"><code>P_fe</code></td><td style="text-align:right;">W</td><td style="text-align:right;">No-load (core / iron) loss</td></tr><tr><td style="text-align:right;">P_ll (load loss)</td><td style="text-align:right;"><code>P_cu</code></td><td style="text-align:right;">W</td><td style="text-align:right;">Total load loss at rated current</td></tr><tr><td style="text-align:right;">P_w</td><td style="text-align:right;">—</td><td style="text-align:right;">W</td><td style="text-align:right;">DC (resistive) component of the winding loss</td></tr><tr><td style="text-align:right;">P_ec</td><td style="text-align:right;">—</td><td style="text-align:right;">W</td><td style="text-align:right;">Eddy-current loss in the windings</td></tr><tr><td style="text-align:right;">P_ll_hv_lv</td><td style="text-align:right;"><code>P_ll_hv_lv</code></td><td style="text-align:right;">W</td><td style="text-align:right;">Short-circuit loss for the HV–LV winding pair</td></tr><tr><td style="text-align:right;">P_ll_hv_mv</td><td style="text-align:right;"><code>P_ll_hv_mv</code></td><td style="text-align:right;">W</td><td style="text-align:right;">Short-circuit loss for the HV–MV winding pair</td></tr><tr><td style="text-align:right;">P_ll_mv_lv</td><td style="text-align:right;"><code>P_ll_mv_lv</code></td><td style="text-align:right;">W</td><td style="text-align:right;">Short-circuit loss for the MV–LV winding pair</td></tr><tr><td style="text-align:right;">P_ll_total</td><td style="text-align:right;"><code>P_ll_total</code></td><td style="text-align:right;">W</td><td style="text-align:right;">Total load loss at rated current (all windings combined)</td></tr></tbody></table><blockquote><p><strong>Note — naming convention.</strong> IEC 60076-7 uses <em>P_o</em> for no-load loss and <em>P_ll</em> for load loss. The code uses <code>P_fe</code> (iron loss) and <code>P_cu</code> (copper loss) instead, which are equally common in the power-systems literature.</p></blockquote><hr><h2 id="IEC-Thermal-Model-Constants" tabindex="-1">IEC Thermal-Model Constants <a class="header-anchor" href="#IEC-Thermal-Model-Constants" aria-label="Permalink to &quot;IEC Thermal-Model Constants {#IEC-Thermal-Model-Constants}&quot;">​</a></h2><p>These appear in the IEC 60076-7 differential equations for top-oil and hot-spot temperature rise.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">k₁₁</td><td style="text-align:right;"><code>k₁₁</code></td><td style="text-align:right;">Oil thermal-model constant (time-constant correction factor)</td></tr><tr><td style="text-align:right;">k₂₁</td><td style="text-align:right;"><code>k₂₁</code></td><td style="text-align:right;">Winding thermal-model constant (initial, undershoot factor)</td></tr><tr><td style="text-align:right;">k₂₂</td><td style="text-align:right;"><code>k₂₂</code></td><td style="text-align:right;">Winding thermal-model constant (final, overshoot factor)</td></tr><tr><td style="text-align:right;">x</td><td style="text-align:right;"><code>x</code> (field) / <code>x_oil</code> (default)</td><td style="text-align:right;">Oil viscosity / loss exponent</td></tr><tr><td style="text-align:right;">y</td><td style="text-align:right;"><code>y</code> (field) / <code>y_wdg</code> (default)</td><td style="text-align:right;">Winding temperature-gradient exponent</td></tr></tbody></table><hr><h2 id="Winding-and-Rated-Parameters" tabindex="-1">Winding and Rated Parameters <a class="header-anchor" href="#Winding-and-Rated-Parameters" aria-label="Permalink to &quot;Winding and Rated Parameters {#Winding-and-Rated-Parameters}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Code name</th><th style="text-align:right;">Unit</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;">Iᵣ (I_rated)</td><td style="text-align:right;"><code>I_r</code></td><td style="text-align:right;">A</td><td style="text-align:right;">Rated current of the winding</td></tr><tr><td style="text-align:right;">Sᵣ (S_rated)</td><td style="text-align:right;"><code>S_r</code></td><td style="text-align:right;">MVA</td><td style="text-align:right;">Rated apparent power of the winding</td></tr><tr><td style="text-align:right;">gᵣ</td><td style="text-align:right;"><code>g_r</code></td><td style="text-align:right;">K</td><td style="text-align:right;">Rated winding-to-oil temperature gradient</td></tr><tr><td style="text-align:right;">H</td><td style="text-align:right;"><code>H</code></td><td style="text-align:right;">—</td><td style="text-align:right;">Hot-spot factor (ratio of winding hot-spot gradient to mean gradient)</td></tr></tbody></table><hr><h2 id="Abbreviations" tabindex="-1">Abbreviations <a class="header-anchor" href="#Abbreviations" aria-label="Permalink to &quot;Abbreviations {#Abbreviations}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Abbreviation</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">ONAN</td><td style="text-align:right;">Oil Natural Air Natural (natural convection, no fans)</td></tr><tr><td style="text-align:right;">ONAF</td><td style="text-align:right;">Oil Natural Air Forced (natural oil circulation, forced-air cooling)</td></tr><tr><td style="text-align:right;">OFAN</td><td style="text-align:right;">Oil Forced Air Natural (forced oil circulation, natural-air cooling)</td></tr><tr><td style="text-align:right;">OFAF</td><td style="text-align:right;">Oil Forced Air Forced (forced oil circulation, forced-air cooling)</td></tr><tr><td style="text-align:right;">ODAF</td><td style="text-align:right;">Oil Directed Air Forced (directed forced oil, forced-air cooling)</td></tr><tr><td style="text-align:right;">IEC</td><td style="text-align:right;">International Electrotechnical Commission</td></tr><tr><td style="text-align:right;">IEEE</td><td style="text-align:right;">Institute of Electrical and Electronics Engineers</td></tr><tr><td style="text-align:right;">LV</td><td style="text-align:right;">Low Voltage winding</td></tr><tr><td style="text-align:right;">MV</td><td style="text-align:right;">Medium Voltage winding</td></tr><tr><td style="text-align:right;">HV</td><td style="text-align:right;">High Voltage winding</td></tr><tr><td style="text-align:right;">MVA</td><td style="text-align:right;">Megavolt-Ampere</td></tr><tr><td style="text-align:right;">p.u.</td><td style="text-align:right;">Per unit (normalised to rated value)</td></tr></tbody></table>',26)])])}const c=e(a,[["render",d]]);export{x as __pageData,c as default};
